// Obtener el primer item de la búsqueda
const searchResult = $input.first().json;

// Variables de control
let hasMoreResults = false;
let nextStartIndex = 0;

// Verificar si existe información de paginación
if (searchResult.serpapi_pagination) {
  const pagination = searchResult.serpapi_pagination;

  // Si existe "next", hay más resultados
  hasMoreResults = !!pagination.next;

  // Calcular el siguiente índice de inicio
  if (hasMoreResults) {
    // Extraer el parámetro "start" de la URL next
    const nextUrl = pagination.next;
    const startMatch = nextUrl.match(/start=(\d+)/);

    if (startMatch) {
      nextStartIndex = parseInt(startMatch[1]);
    } else {
      // Si no encuentra start en la URL, calcular manualmente
      nextStartIndex = (pagination.current * 10);
    }
  }
}

// Log para debugging
console.log('Página actual:', searchResult.serpapi_pagination?.current || 1);
console.log('¿Hay más resultados?:', hasMoreResults);
console.log('Siguiente start index:', nextStartIndex);

// Retornar valores de control
return {
  json: {
    continueLoop: hasMoreResults,
    startIndex: nextStartIndex,
    currentPage: searchResult.serpapi_pagination?.current || 1
  }
};

const response = $input.first().json;
const organicResults = response.organic_results || [];

// Gestionar la paginación de SerpApi
const nextLink = response.serpapi_pagination?.next || null;
const hasMoreResults = !!nextLink; 

// procesar informacion de busqueda
const search_information = response.search_information.query_displayed;

// Procesar los resultados
const results = organicResults.map(item => {
  const title = item.title || "";
  const snippet = item.snippet || "";
  const source = item.source || "";

  // Limpiar el name desde "source"
  // Elimina prefijos como "LinkedIn · ", "Twitter · ", etc.
  let cleanName = source
    .replace(/^(LinkedIn|Twitter|Facebook|Instagram|YouTube)\s*[·•·-]\s*/i, '')
    .trim();

  // Si no hay source, intentar obtener el name desde title
  if (!cleanName && title) {
    const titleParts = title.split(" - ");
    cleanName = titleParts[0]?.trim() || null;
  }

  // Limpiar el title (obtener solo la parte después del guión)
  // "Christiana Riley - President and CEO, Santander US" -> "President and CEO, Santander US"
  let cleanTitle = null;
  if (title.includes(" - ")) {
    const titleParts = title.split(" - ");
    // Tomamos todo después del primer guión
    cleanTitle = titleParts.slice(1).join(" - ").trim();
  } else {
    cleanTitle = title.trim();
  }

  return {
    // Datos limpios para la BD
    name: cleanName || null,
    title: cleanTitle || null,
    link: item.link || null,
    //sector: $('Code in JavaScript').first().json.Sector,
    //image: item.favicon || null,

    // Contexto enriquecido para OpenRouter
    // Enviamos tanto el título como el snippet para que la IA tenga más contexto
    ai_prompt_context: `Nombre: ${cleanName}. Cargo: ${cleanTitle}. Resumen: ${snippet}`,
    search_information: search_information,
    // Info para el Loop de n8n
    nextPageLink: nextLink
    //hasMoreResults: hasMoreResults
  };
});

if (results.length === 0) {
  return [{ 
    json: { name: null, title: null, hasMoreResults: false }
  }];
}

return results.map(r => ({ json: r }));

