// Código mejorado para limpiar HTML antes de procesarlo con IA
const item = $input.first().json;
let htmlFinal = "";

// 1. Obtener el contenido HTML
const binaryData = $input.first().binary;
if (binaryData && binaryData.data) {
    htmlFinal = Buffer.from(binaryData.data.data, 'base64').toString('utf8');
} else if (typeof item.data === 'string') {
    htmlFinal = item.data;
} else if (typeof item.data === 'object') {
    htmlFinal = JSON.stringify(item.data);
}

// 2. Limpieza avanzada del HTML
htmlFinal = htmlFinal
    // Eliminar scripts y estilos completos
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
    .replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, '')
    // Eliminar comentarios HTML
    .replace(/<!--[\s\S]*?-->/g, '')
    // Eliminar meta tags y links
    .replace(/<meta[^>]*>/gi, '')
    .replace(/<link[^>]*>/gi, '')
    // Eliminar tags de header innecesarios
    .replace(/<head[^>]*>[\s\S]*?<\/head>/gi, '')
    // Convertir saltos de línea de HTML a espacios
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<\/p>/gi, ' ')
    .replace(/<\/div>/gi, ' ')
    .replace(/<\/li>/gi, ' ')
    // Eliminar todas las etiquetas HTML restantes pero conservar el contenido
    .replace(/<[^>]+>/g, ' ')
    // Decodificar entidades HTML comunes
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    // Limpiar espacios múltiples, tabs y saltos de línea
    .replace(/\s+/g, ' ')
    // Eliminar espacios al inicio y final
    .trim()
    // Limitar longitud (ajusta según necesites)
    .substring(0, 8000);

